INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 16, "東山奈央", 100101, "人助けが大好き！　前向き格闘娘", "人助け、応援", 155, 27, "獣人族", "トゥインクルウィッシュ", 8, "A", "ヒヨリ", 44, 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 17, "種田梨沙", 100201, "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", 158, 5, "ヒューマン", "トゥインクルウィッシュ", 4, "O", "ユイ", 47, 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 18, "早見沙織", 100301, "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", 163, 12, "魔族", "トゥインクルウィッシュ", 1, "B", "レイ", 46, 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 9, "諸星すみれ", 100401, "探検好きのイタズラっ子", "いたずら、探検", 128, 10, "ヒューマン", "リトルリリカル", 8, "O", "ミソギ", 27, 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "？？？", 12, "下田麻美", 100501, "ヒーローに憧れる騎士見習いの少女", "ヒーローごっこ", 146, 25, "獣人族", "王宮騎士団（NIGHTMARE）", 11, "O", "マツリ", 40, 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 13, "浅倉杏美", 100601, "甘え上手なみんなの人気者", "サックス", 150, 22, "魔族", "悪魔偽王国軍（ディアボロス）", 11, "O", "アカリ", 42, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 14, "雨宮天", 100701, "プリン大好きゴースト娘", "プリンを食べること", 130, 23, "魔族", "悪魔偽王国軍（ディアボロス）", 1, "B", "ミヤコ", 32, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 14, "大空直美", 100801, "ボクは誰よりも美しい", "鏡で自分を見ること", 150, 10, "エルフ", "ヴァイスフリューゲル　ランドソル支部", 10, "AB", "ユキ", 40, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 17, "髙野麻美", 100901, "前世を信じる中二病患者、「疾風の冥姫」", "小説執筆", 159, 5, "魔族", "トワイライトキャラバン", 7, "A", "アンナ", 45, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 16, "内田真礼", 101001, "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", 155, 22, "獣人族", "自警団（カォン）", 9, "O", "マホ", 42, 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 15, "阿澄佳奈", 101101, "人懐っこくてマシンガントークな妹系少女", "お裁縫", 156, 25, "ヒューマン", "ラビリンス", 8, "A", "リノ", 44, 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 17, "大橋彩香", 101201, "みんなのために超能力を使う眠り姫", "妹と遊ぶこと、二度寝、昼寝、早寝", 156, 24, "エルフ", "フォレスティエ", 12, "A", "ハツネ", 46, 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "", 18, "佳村はるか", 101301, "オタク全開な魔法少女", "読書、魔法", 166, 21, "魔族", "トワイライトキャラバン", 8, "O", "ナナカ", 55, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "test", 15, "水瀬いのり", 101401, "頭脳明晰な美少女名探偵", "読書、推理", 152, 3, "獣人族", "自警団（カォン）", 11, "AB", "カスミ", 41, 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "test", 21, "國府田マリ子", 101501, "母性溢れる優しいみんなの「ミサト先生」", "絵本作り", 165, 5, "エルフ", "フォレスティエ", 9, "O", "ミサト", 54, 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 17, "上坂すみれ", 101601, "天真爛漫で人気者のカリスマモデル", "ファッション", 167, 10, "魔族", "ルーセント学院", 4, "O", "スズナ", 48, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 17, "高森奈津美", 101701, "いつでも「なんくるないさ～」な天然娘", "踊り、空手", 158, 7, "獣人族", "自警団（カォン）", 7, "A", "カオリ", 53, 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 23, "伊藤静", 101801, "多くの男性を魅了する無垢な女教師", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 162, 14, "魔族", "ルーセント学院", 8, "B", "イオ", 52, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 10, "日高里菜", 102001, "お歌もにんじんも、ウサギさんも大好き♪", "かわいいもの集め", 117, 3, "獣人族", "リトルリリカル", 4, "O", "ミミ", 21, 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 12, "植田佳奈", 102101, "泣き虫で臆病な守ってあげたい女の子", "観劇、おままごと", 150, 9, "ヒューマン", "サレンディア救護院", 6, "B", "クルミ", 40, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 13, "原紗友里", 102201, "人見知りであまのじゃくな女の子", "ゲーム全般", 150, 22, "魔族", "悪魔偽王国軍（ディアボロス）", 11, "O", "ヨリ", 40, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 14, "芹澤優", 102301, "ぷうきちといつも一緒！", "屋内でできる遊び", 148, 10, "ヒューマン", "サレンディア救護院", 5, "B", "アヤネ", 38, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 15, "悠木碧", 102501, "お嬢さまのためにがんばるドジっ娘メイド", "ご奉仕", 154, 12, "ヒューマン", "サレンディア救護院", 12, "O", "スズメ", 43, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "test", 17, "小岩井ことり", 102601, "遊びと睡眠が何より大事なぐうたら娘", "あんパン", 144, 1, "獣人族", "牧場（エリザベスパーク）", 1, "B", "リン", 42, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 16, "橋本ちなみ", 102701, "運命の相手に一途すぎる乙女", "実験、裁縫、料理", 154, 30, "魔族", "トワイライトキャラバン", 7, "B", "エリコ", 43, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 17, "堀江由衣", 102801, "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", 156, 4, "エルフ", "サレンディア救護院", 10, "A", "サレン", 43, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 17, "日笠陽子", 102901, "歌って踊れる大人気アイドル", "舞台鑑賞、ダンス", 157, 24, "ヒューマン", "カルミナ", 1, "B", "ノゾミ", 40, 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 16, "佐藤聡美", 103001, "トーゴクの神秘、オシエテクダサイ！", "忍法開発", 163, 31, "ヒューマン", "ヴァイスフリューゲル　ランドソル支部", 8, "O", "ニノン", 51, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 18, "大坪由佳", 103101, "占いが得意な霊能少女", "占い", 157, 22, "魔族", "悪魔偽王国軍（ディアボロス）", 12, "AB", "シノブ", 42, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 18, "松嵜麗", 103201, "一人前の商人を目指すパワフルお嬢様", "慈善事業", 157, 12, "ヒューマン", "メルクリウス財団", 3, "AB", "アキノ", 45, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 20, "新田恵海", 103301, "みんなを笑顔にするお笑い牧場主", "漫才", 142, 3, "ヒューマン", "牧場（エリザベスパーク）", 3, "B", "マヒル", 35, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 22, "今井麻美", 103401, "純情でほっとけない大人の女性", "ウインドーショッピング", 164, 16, "エルフ", "メルクリウス財団", 3, "A", "ユカリ", 55, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "test", 8, "小倉唯", 103601, "礼儀正しくしっかり者のちびっ子優等生", "お勉強", 118, 2, "エルフ", "リトルリリカル", 2, "A", "キョウカ", 21, 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "test", 13, "茅原実里", 103701, "義理堅くてからかい好きな剣術少女", "剣術、年長者をからかう", 149, 11, "ヒューマン", "王宮騎士団（NIGHTMARE）", 8, "A", "トモ", 43, 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 14, "小清水亜美", 103801, "読書が趣味の病弱少女", "読書、お散歩", 153, 3, "獣人族", "牧場（エリザベスパーク）", 11, "A", "シオリ", 40, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 13, "花澤香菜", 104001, "「友達」に憧れる、エルフの森の女の子", "友達作りのイメトレ", 158, 6, "エルフ", "フォレスティエ", 6, "AB", "アオイ", 44, 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 17, "福原綾香", 104201, "人々を守るために歌う、唱喚士の少女", "各種楽器", 163, 3, "ヒューマン", "カルミナ", 6, "O", "チカ", 46, 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 17, "小松未可子", 104301, "男勝りで情に厚いワイルド娘", "お菓子作り", 168, 9, "獣人族", "自警団（カォン）", 8, "O", "マコト", 54, 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "test", "??", "丹下桜", 104401, "かつては夜を支配した最強の吸血鬼", "世界征服", 172, 5, "魔族", "悪魔偽王国軍（ディアボロス）", 5, "A", "イリヤ", 50, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 18, "長妻樹里", 104501, "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", 157, 19, "ヒューマン", "ヴァイスフリューゲル　ランドソル支部", 11, "AB", "クウカ", 49, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 19, "沼倉愛美", 104601, "弱きを助け強きをくじく猫娘", "猫とたわむれること", 158, 1, "獣人族", "メルクリウス財団", 3, "AB", "タマキ", 48, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "？？？", 25, "川澄綾子", 104701, "素顔を見せない冷静沈着な女性騎士", "格闘技、湯浴み", 171, 25, "ヒューマン", "王宮騎士団（NIGHTMARE）", 10, "A", "ジュン", 50, 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 20, "田所あずさ", 104801, "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", 163, 11, "ヒューマン", "メルクリウス財団", 11, "O", "ミフユ", 49, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 18, "生天目仁美", 104901, "お姉ちゃんがお世話してあげるからねっ！", "家事全般", 168, 24, "ヒューマン", "ラビリンス", 10, "O", "シズル", 54, 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 11, "久野美咲", 105001, "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", 120, 3, "魔族", "ルーセント学院", 1, "A", "ミサキ", 22, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 27, "三石琴乃", 105101, "実験が趣味の危険な科学者", "研究、実験", 166, 7, "ヒューマン", "トワイライトキャラバン", 3, "A", "ミツキ", 53, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 17, "徳井青空", 105201, "乙女チックなもふもふアニマル", "毛繕い、お喋り", 150, 14, "獣人族", "牧場（エリザベスパーク）", 3, "A", "リマ", 100, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 17, "辻あゆみ", 105301, "見た目も中身もお子ちゃまな異国の軍人", "お菓子屋通い", 140, 28, "ヒューマン", "ヴァイスフリューゲル　ランドソル支部", 7, "A", "モニカ", 33, 15);
