INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 15, "悠木碧", 107701, "お嬢さまのためにがんばるドジっ娘メイド", "ご奉仕", 154, 12, "ヒューマン", "サレンディア救護院", 12, "O", "スズメ（サマー）", 43, 9);
