INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 19, "沼倉愛美", 107901, "弱きを助け強きをくじく猫娘", "猫とたわむれること", 158, 1, "獣人族", "メルクリウス財団", 3, "AB", "タマキ（サマー）", 48, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 20, "田所あずさ", 108001, "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", 163, 11, "ヒューマン", "メルクリウス財団", 11, "O", "ミフユ（サマー）", 49, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 18, "大坪由佳", 108101, "占いが得意な霊能少女", "占い", 157, 22, "魔族", "悪魔偽王国軍（ディアボロス）", 12, "AB", "シノブ（ハロウィン）", 42, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 14, "雨宮天", 108201, "プリン大好きゴースト娘", "プリンを食べること", 130, 23, "魔族", "悪魔偽王国軍（ディアボロス）", 1, "B", "ミヤコ（ハロウィン）", 32, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 11, "久野美咲", 108301, "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", 120, 3, "魔族", "ルーセント学院", 1, "A", "ミサキ（ハロウィン）", 22, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 17, "福原綾香", 108401, "人々を守るために歌う、唱喚士の少女", "各種楽器", 163, 3, "ヒューマン", "カルミナ", 6, "O", "チカ（クリスマス）", 46, 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 12, "植田佳奈", 108501, "泣き虫で臆病な守ってあげたい女の子", "観劇、おままごと", 150, 9, "ヒューマン", "サレンディア救護院", 6, "B", "クルミ（クリスマス）", 40, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 14, "芹澤優", 108601, "ぷうきちといつも一緒！", "屋内でできる遊び", 148, 10, "ヒューマン", "サレンディア救護院", 5, "B", "アヤネ（クリスマス）", 38, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 16, "東山奈央", 108701, "人助けが大好き！　前向き格闘娘", "人助け、応援", 155, 27, "獣人族", "トゥインクルウィッシュ", 8, "A", "ヒヨリ（ニューイヤー）", 44, 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 17, "種田梨沙", 108801, "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", 158, 5, "ヒューマン", "トゥインクルウィッシュ", 4, "O", "ユイ（ニューイヤー）", 47, 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 18, "早見沙織", 108901, "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", 163, 12, "魔族", "トゥインクルウィッシュ", 1, "B", "レイ（ニューイヤー）", 46, 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 16, "橋本ちなみ", 109001, "運命の相手に一途すぎる乙女", "実験、裁縫、料理", 154, 30, "魔族", "トワイライトキャラバン", 7, "B", "エリコ（バレンタイン）", 43, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 18, "生天目仁美", 109101, "お姉ちゃんがお世話してあげるからねっ！", "家事全般", 168, 24, "ヒューマン", "ラビリンス", 10, "O", "シズル（バレンタイン）", 54, 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 17, "日笠陽子", 109201, "英霊と契約を結んだマナリアの天才王女", "読書", 156, 1, "ヒューマン", "？？？", 12, "AB", "アン", 55, "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 16, "こやまきみこ", 109301, "マナリア魔法学院の新入生", "食べること、眠ること", 144, 4, "ヒューマン", "？？？", 2, "O", "ルゥ", 45, "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 17, "福原綾香", 109401, "人を超越した力を有す心優しい竜姫", "ピアノ", 167, 3, "半人半竜", "？？？", 11, "B", "グレア", 67, "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 18, "長妻樹里", 109501, "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", 157, 19, "ヒューマン", "ヴァイスフリューゲル　ランドソル支部", 11, "AB", "クウカ（オーエド）", 49, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 16, "佐藤聡美", 109601, "トーゴクの神秘、オシエテクダサイ！", "忍法開発", 163, 31, "ヒューマン", "ヴァイスフリューゲル　ランドソル支部", 8, "O", "ニノン（オーエド）", 51, 15);
