INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 16, "内田真礼", 116001, "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", 155, 22, "獣人族", "自警団（カォン）", 9, "O", "マホ（シンデレラ）", 42, 10);
