INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 19, "沼倉愛美", 116801, "弱きを助け強きをくじく猫娘", "猫とたわむれること", 158, 1, "獣人族", "メルクリウス財団", 3, "AB", "タマキ（作業服）", 48, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 20, "田所あずさ", 116901, "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", 163, 11, "ヒューマン", "メルクリウス財団", 11, "O", "ミフユ（作業服）", 49, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 16, "橋本ちなみ", 117001, "運命の相手に一途すぎる乙女", "実験、裁縫、料理", 154, 30, "魔族", "トワイライトキャラバン", 7, "B", "エリコ（サマー）", 43, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 18, "生天目仁美", 117101, "お姉ちゃんがお世話してあげるからねっ！", "家事全般", 168, 24, "ヒューマン", "ラビリンス", 10, "O", "シズル（サマー）", 54, 3);
