INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 17, "福原綾香", 117301, "人々を守るために歌う、唱喚士の少女", "各種楽器", 163, 3, "ヒューマン", "カルミナ", 6, "O", "チカ（サマー）", 46, 4);
