INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 17, "髙野麻美", 121901, "前世を信じる中二病患者、「疾風の冥姫」", "小説執筆", 159, 5, "魔族", "トワイライトキャラバン", 7, "A", "アンナ（パイレーツ）", 45, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 18, "大坪由佳", 122001, "占いが得意な霊能少女", "占い", 157, 22, "魔族", "悪魔偽王国軍（ディアボロス）", 12, "AB", "シノブ（パイレーツ）", 42, 7);
