INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 18, "長妻樹里", 127001, "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", 157, 19, "ヒューマン", "ヴァイスフリューゲル　ランドソル支部", 11, "AB", "クウカ（サマー）", 49, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 18, "大坪由佳", 127101, "占いが得意な霊能少女", "占い", 157, 22, "魔族", "悪魔偽王国軍（ディアボロス）", 12, "AB", "シノブ（サマー）", 42, 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 14, "立花理香", 127201, "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", 152, 2, "獣人族", "美食殿", 9, "A", "キャル（編入生）", 39, 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 17, "上坂すみれ", 127301, "天真爛漫で人気者のカリスマモデル", "ファッション", 167, 10, "魔族", "ルーセント学院", 4, "O", "スズナ（編入生）", 48, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 17, "堀江由衣", 127501, "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", 156, 4, "エルフ", "サレンディア救護院", 10, "A", "サレン（サラサリア）", 43, 9);
