INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 17, "種田梨沙", 180201, "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", 158, 5, "ヒューマン", "トゥインクルウィッシュ", 4, "O", "ユイ（プリンセス）", 47, 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 18, "早見沙織", 180301, "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", 163, 12, "魔族", "トゥインクルウィッシュ", 1, "B", "レイ（プリンセス）", 46, 2);
