INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 11, "伊藤美来", 180501, "主を慕う、小さなガイド役", "瞑想、動植物の飼育", 140, 11, "エルフ", "美食殿", 5, "B", "コッコロ（プリンセス）", 35, 1);
